/* Make links glow when I hover over them */
a:hover {
  text-shadow: 0 0 10px var(--accent);
}

/* Add a subtle scanline effect to the background (Dead Space vibe) */
body::before {
  content: " ";
  display: block;
  position: fixed;
  top: 0; left: 0; bottom: 0; right: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.1) 50%), 
              linear-gradient(90deg, rgba(255, 0, 0, 0.02), rgba(0, 255, 0, 0.01), rgba(0, 0, 255, 0.02));
  z-index: 9999;
  pointer-events: none;
  background-size: 100% 2px, 3px 100%;
}
/* Change the Apple Blue to your chosen Accent Color */
:root {
  --accent: #f1f704; /* Matches the yellow in your screenshot */
}

/* Add the Apple Panel Styling */
.card {
  background: rgba(28, 28, 30, 0.7);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 22px;
  padding: 30px;
  transition: transform 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.card:hover {
  transform: scale(1.02);
  border-color: var(--accent);
}
/* 1. MAKE SOUND DESIGN PANEL WIDE & AMBER */
#sound-design-grid {
  grid-column: span 8; /* Takes up 2/3 of the screen */
  border-left: 4px solid #ff8800; /* Amber accent for Sound Design */
  background: rgba(255, 136, 0, 0.05);
}

/* 2. MAKE COMPOSITION PANEL TALL & BLUE */
#composition-grid {
  grid-column: span 4; /* Takes up 1/3 of the screen */
  border-left: 4px solid #0071e3; /* Apple Blue for Composition */
  background: rgba(0, 113, 227, 0.05);
}

/* 3. MAKE PHOTO PANEL A FULL-WIDTH "GALLERY" */
#photo-grid {
  grid-column: span 12; /* Spans the whole page */
  display: flex;
  overflow-x: scroll; /* Makes it swipeable like an iPhone gallery */
  gap: 20px;
  padding: 40px;
}
